$$, $$1137496f90d698f5e5ce0751f2b38a1dee862314833cad5a0f312305cf36cdb1$$, $${"A": "648e18be7e811ffa82bff56ef8ae39916e4b35c7e991e78a967b3ad6795a986e", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "21b43b75efd1c6ec1147fd8561d8df632eb68bbe541f76acb9a821bb55ff6bc7"}$$::jsonb, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$, 233, $$2026-05-10T04:04:17.793201+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0207136F$$, 2027, $$The Manned Destructive Suppression (MDS) program funds the development and sustainment of the Air Force's Suppression of Enemy Air Defenses (SEAD) and
Destruction of Enemy Air Defenses (DEAD) capabilities. The F-16 High-speed Anti-Radiation Missile (HARM) Targeting System (HTS) is currently the only programmed
reactive SEAD/DEAD capability and enables targeting the HARM missile in its most lethal 'range known' mode. The program provides F-16 Block 50/52 and Block 40/42
aircraft with the ability to employ the AN/ASQ-213 targeting Pod. The AN/ASQ-213 Pod also has a precision geo-location capability to target Precision Guided Munitions
(PGMs) to destroy fixed and mobile enemy air defense elements. Additionally, by relocating the AN/ASQ-213 HTS R7 Pod on the aircraft, the F-16 can simultaneously
carry the HTS R7 Pod and an Advanced Targeting Pod (ATP). HTS R7 fielding is complete and represents the Air Force's near-term solution for reactive time-critical
targeting for DEAD until this mission can be transferred to the F-35. HTS R7 derived precision targeting data can be provided to all Joint Forces via Link-16. This effort
continues upgrades for the HTS and applies technologies similar to those demonstrated in the Advanced Tactical Targeting Technologies (AT3) program and HTS R7
development.

 Funds may be used to address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues.

 HTS leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility,
 security and IT upgrades; common component development with other weapon systems to reduce redundant costs.

 This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in
 addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F.

 This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been
 fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.

